-- ── 8. Student sessions ──────────────────────────────────────────────
-- II B.Sc Chemistry → section A
INSERT INTO student_session (session_id, student_id, class_id, section_id, is_active, is_alumni)
  SELECT 21, s.id, cs.class_id, cs.section_id, 'yes', 0
  FROM students s
  JOIN classes c ON LOWER(c.class)=LOWER('II B.Sc Chemistry')
  JOIN sections sec ON LOWER(sec.section)=LOWER('A')
  JOIN class_sections cs ON cs.class_id=c.id AND cs.section_id=sec.id
  WHERE s.note='IMP_MAASC_2025' AND s.admission_no IN (
    '2031', '1914', '1742', '904', '1913', '1706', '1987', '1865', '2057', '2075', '1869', '1903', '1679', '1890', '2085', '1842', '1006', '1889', '2049', '1676', '1677', '2068'
  )
  AND NOT EXISTS (
    SELECT 1 FROM student_session ss2
    WHERE ss2.session_id=21 AND ss2.student_id=s.id
  );

