-- ── 9. Student user accounts ─────────────────────────────────────────
INSERT INTO users (user_id, username, password, childs, role, lang_id, currency_id, verification_code, is_active)
SELECT s.id, CONCAT('std', s.id), 'Welcome@123', '', 'student', 4, 68, '', 'yes'
FROM students s WHERE s.note='IMP_MAASC_2025'
AND NOT EXISTS (SELECT 1 FROM users u WHERE u.user_id=s.id AND u.role='student');

-- Parent user accounts
INSERT INTO users (user_id, username, password, childs, role, lang_id, currency_id, verification_code, is_active)
SELECT s.id, CONCAT('par', s.id), 'Welcome@123', s.id, 'parent', 4, 68, '', 'yes'
FROM students s WHERE s.note='IMP_MAASC_2025'
AND NOT EXISTS (SELECT 1 FROM users u WHERE u.username=CONCAT('par', s.id) AND u.role='parent');

-- Set parent_id on students
UPDATE students s
JOIN users u ON u.username=CONCAT('par', s.id) AND u.role='parent'
SET s.parent_id=u.id
WHERE s.note='IMP_MAASC_2025';

SET FOREIGN_KEY_CHECKS = 1;
